import React from "react";
import FeatureDetail from "./FeatureDetail";

const pageData = {
  title: "SOAR & Playbooks",
  subtitle: "Security Orchestration, Automation, and Response playbooks",
  description: "Automate your incident response with our comprehensive Security Orchestration, Automation, and Response (SOAR) platform. Create customizable playbooks that automatically contain threats, coordinate responses across tools, and learn from every incident to improve future responses.",
  benefits: [
    "Playbook-driven incident response automation",
    "Automated threat containment across your infrastructure",
    "Integration with 500+ security tools and platforms",
    "Autonomous Security Agents for continuous monitoring",
    "Custom workflow automation for any security scenario"
  ],
  features: [
    { title: "Visual Playbook Builder", description: "Drag-and-drop interface for creating automated responses" },
    { title: "Pre-Built Templates", description: "Library of ready-to-use playbooks for common scenarios" },
    { title: "Tool Integrations", description: "Connect with 500+ security tools via API integrations" },
    { title: "Orchestration Engine", description: "Coordinate complex multi-step response workflows" },
    { title: "Learning System", description: "AI that improves playbooks based on incident outcomes" }
  ],
  howItWorks: [
    { title: "Trigger Detection", description: "System detects security event or receives external alert" },
    { title: "Playbook Execution", description: "Automated workflow begins executing defined steps" },
    { title: "Tool Coordination", description: "Actions are coordinated across all integrated tools" },
    { title: "Resolution & Learning", description: "Incident is resolved and system learns for future" }
  ],
  color: "#f59e0b",
  icon: "M9 3v2m6-2v2M9 19v2m6-2v2M5 9H3m2 6H3m18-6h-2m2 6h-2M7 19h10a2 2 0 002-2V7a2 2 0 00-2-2H7a2 2 0 00-2 2v10a2 2 0 002 2zM9 9h6v6H9V9z",
  gradient: "from-amber-500 to-orange-500"
};

function SOAR() {
  return <FeatureDetail {...pageData} />;
}

export default SOAR;
